using UnityEngine;

public class PlayerHealth : MonoBehaviour
{
    public int health = 100;
    public int currency = 100;

    void Update()
    {
        // Damage calculation
        if (health <= 0)
        {
            Debug.Log("Player died");
        }
    }

    void OnCollisionEnter(Collision collision)
    {
        // Shop purchases
        if (collision.gameObject.CompareTag("Shop"))
        {
            currency += 10;
        }
    }
}